import{_ as p,P as e,Q as t,a3 as a}from"./framework-62102715.js";const c={},o=a('<h2 id="弘一法师经典" tabindex="-1"><a class="header-anchor" href="#弘一法师经典" aria-hidden="true">#</a> 弘一法师经典</h2><p>弘一法师曾说过一句很有名的话：“物来顺应，未来不迎，当时不杂，既过不恋。”</p><p>弘一法师说：“以淡泊之心面对世事，以美好之心看待人生。”</p><p>1、君子之交，其淡如水；执象而求，咫尺千里。</p><p>2、天之涯，地之角，知交半零落。一壶浊酒尽余欢，今宵别梦寒。</p><p>3、行矣临流重叹息，说相思，刻骨双红豆。</p><p>4、处难处之事宜宽，处难处之人宜厚，处至急之事宜缓。</p><p>5、有出格见地，方有千古品格；有千古品格，方有超凡学问，有超凡学问，方有盖世文章。</p><p>6、佛祖奚以异于人，而所以异于人者，能自护心念耳。</p><p>7、诸位要晓得，我的性情是很特别的，我只希望我的事情失败，因为事情失败，不完美，这才使我常常惭愧！能够晓得自己的德行欠缺，自己的修善不足，那我才可努力用功，努力改过迁善。</p><p>8、能受锻炼，便如松柏， 历岁寒而愈坚，不受，则如夏草春花，甫遇风霜，颓靡无似矣。</p><p>9、有识量无品格，不足以砥柱中流，犹无识量也。</p><p>10、用功夫如穿针引线，急不得， 粗不得，要仔细专注耐烦才行。</p><p>14、不自重者，取辱；不自畏者，招祸。</p><p>15、群居，守口；独处，防心。</p><p>16、己性不可任，当用逆法制之，其道在一“忍”字。</p><p>17、静坐常思己过，闲谈莫论人非。</p><p>18、为善最乐，读书便佳。</p><p>19、一蟹失足，二蟹扶持。物知慈悲人何不如？</p><p>20、水边垂钓，闲情逸致。是以物命，而为儿戏。 刺骨穿肠，于心何忍。愿发仁慈，常起悲悯。</p><p>21、安莫安于知足，危莫危于多言。</p><p>22、不为外物所动之谓静，不为外物所实之谓虚。</p>',22),r=[o];function n(s,_){return e(),t("div",null,r)}const i=p(c,[["render",n],["__file","poem01.html.vue"]]);export{i as default};
